    }
  }
}];

const keywords = $input.first().json.keywords || '';

if (!keywords) {
  throw new Error('keywords parameter is required');
}

return [{
  json: {
    keywords: keywords
  }
}];

const response = $input.first().json;
const keywords = $('准备搜索请求').first().json.keywords;
const inputData = $('标准化输入').first().json;
const room = inputData.room || 'qa';

if (response.error || response.errcode) {
  return [{
    json: {
      success: false,
      error: response.error || response.message || 'RAGFlow 检索失败',
      room: room
    }
  }];
}

const cleanText = (value = '') => String(value)
  .replace(/[\[\]()#*>|!]/g, '')
  .replace(/\s+/g, ' ')
  .trim();

const chunks = Array.isArray(response.data?.chunks) ? response.data.chunks : [];
const normalizedChunks = chunks.map((chunk) => ({
  docName: String(chunk.document_keyword || chunk.doc_name || '未知文档').replace(/\.md$/, ''),
  similarity: chunk.similarity ? Math.round(chunk.similarity * 100) : 0,
  snippet: cleanText(chunk.content || '')
}));

// 按文档名去重 — 每篇文档保留最高相似度的一条
const bestByDoc = {};
for (const chunk of normalizedChunks) {
  const existing = bestByDoc[chunk.docName];
  if (!existing || chunk.similarity > existing.similarity) {
    bestByDoc[chunk.docName] = chunk;
  }
}
const dedupedChunks = Object.values(bestByDoc).sort((a, b) => (b.similarity || 0) - (a.similarity || 0));
const totalChunks = normalizedChunks.length;
const uniqueDocs = dedupedChunks.length;
const topChunks = dedupedChunks.slice(0, 10);

if (uniqueDocs === 0) {
  return [{
    json: {
      success: true,
      message: `🔍 知识库搜索\n\n关键词：${keywords}\n\n未找到相关内容`,
      room: room
    }
  }];
}

let message = `🔍 知识库搜索\n\n关键词：${keywords}\n\n## 匹配结果`;

topChunks.forEach((chunk, i) => {
  const score = chunk.similarity ? ` (${chunk.similarity}%)` : '';
  message += `\n${i + 1}. ${chunk.docName}${score}`;
  if (chunk.snippet) {
    const snippet = chunk.snippet.slice(0, 120);
    const suffix = chunk.snippet.length > 120 ? '...' : '';
    message += `\n摘要：${snippet}${suffix}`;
  }
});

if (uniqueDocs > 10) {
  message += `\n\n... 等共 ${uniqueDocs} 篇文档（${totalChunks} 条相关片段）`;
} else {
  message += `\n\n## 结果统计\n共找到 ${uniqueDocs} 篇文档`;
}

const data = $input.first().json;
const room = data.room || 'qa';

const escapeHtml = (text = '') => String(text)
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;');

const formatInline = (text = '') => escapeHtml(text)
  .replace(/\*\*(.+?)\*\*/g, '<b>$1</b>')
  .replace(/`([^`]+)`/g, '<code>$1</code>');

const renderMessage = (rawMessage) => {
  const lines = String(rawMessage || '').split('\n');
  const htmlParts = [];
  let inOrderedList = false;
  let listItemOpen = false;

  const closeListItem = () => {
    if (listItemOpen) {
      htmlParts.push('</li>');
      listItemOpen = false;
    }
  };

  const closeOrderedList = () => {
    closeListItem();
    if (inOrderedList) {
      htmlParts.push('</ol>');
      inOrderedList = false;
    }
  };

  for (const rawLine of lines) {
    const trimmed = rawLine.trim();

    if (!trimmed) {
      closeListItem();
      continue;
    }

    if (/^[📘🔍🤖]/.test(trimmed)) {
      closeOrderedList();
      htmlParts.push(`<h4>${formatInline(trimmed)}</h4>`);
      continue;
    }

    if (/^(问题|关键词)：/.test(trimmed)) {
      closeOrderedList();
      htmlParts.push(`<p><em>${formatInline(trimmed)}</em></p>`);
      continue;
    }

    const h2Match = trimmed.match(/^##\s+(.+)$/);
    if (h2Match) {
      closeOrderedList();
      htmlParts.push(`<h5>${formatInline(h2Match[1])}</h5>`);
      continue;
    }

    const numMatch = trimmed.match(/^(\d+)\.\s+(.+)$/);
    if (numMatch) {
      if (!inOrderedList) {
        htmlParts.push('<ol>');
        inOrderedList = true;
      }
      closeListItem();
      htmlParts.push('<li>');
      htmlParts.push(`<p>${formatInline(numMatch[2])}</p>`);
      listItemOpen = true;
      continue;
    }

    const summaryMatch = trimmed.match(/^摘要：(.+)$/);
    if (summaryMatch) {
      const summaryHtml = `<blockquote>${formatInline(summaryMatch[1].trim())}</blockquote>`;
      if (listItemOpen) {
        htmlParts.push(summaryHtml);
      } else {
        closeOrderedList();
        htmlParts.push(summaryHtml);
      }
      continue;
    }

    const bulletMatch = trimmed.match(/^[*\-•]\s+(.+)$/);
    if (bulletMatch) {
      closeOrderedList();
      htmlParts.push(`<p>• ${formatInline(bulletMatch[1])}</p>`);
      continue;
    }

    if (listItemOpen) {
      htmlParts.push(`<p>${formatInline(trimmed)}</p>`);
      continue;
    }

    closeOrderedList();
    htmlParts.push(`<p>${formatInline(trimmed)}</p>`);
  }

  closeOrderedList();
  return htmlParts.join('\n');
};

let message = '';
let html = '';

if (data.success === false || data.error) {
  const errMsg = typeof data.error === 'object' ? (data.error.message || JSON.stringify(data.error)) : String(data.error || '未知错误');
  message = `❌ 操作失败: ${errMsg}`;
  html = `<p>❌ 操作失败: ${formatInline(errMsg)}</p>`;
} else if (data.message) {
  message = data.message;
  html = renderMessage(message);
} else {
  message = '✅ 操作成功';
  html = '<p>✅ 操作成功</p>';
}

return [{ json: { room, message, html } }];

